--
-- Table structure for table `grades`
--

DROP TABLE IF EXISTS `grades`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `grades` (
  `grade_id` int(11) NOT NULL AUTO_INCREMENT,
  `enrollment_id` int(11) NOT NULL,
  `student_id` int(11) NOT NULL,
  `section_id` int(11) NOT NULL,
  `midterm` decimal(5,2) DEFAULT NULL,
  `final` decimal(5,2) DEFAULT NULL,
  `grade` decimal(5,2) DEFAULT NULL COMMENT 'Final computed grade',
  `remarks` varchar(20) DEFAULT NULL COMMENT 'Passed, Failed, INC, etc.',
  `status` enum('pending','submitted','approved','rejected') DEFAULT 'pending',
  `submitted_by` int(11) DEFAULT NULL COMMENT 'Instructor who submitted',
  `submitted_at` datetime DEFAULT NULL,
